export interface PrUrlReportedEventPayload {
  ticket_id: string;
  url: string;
}

// ── Helper to create typed event wrappers ──

function createEvent<T>(name: string) {
  return {
    listen: (handler: (event: { payload: T }) => void): Promise<UnlistenFn> =>
      listen<T>(name, handler),
  };
}

