// ── Events ──
// Event names match the Rust struct names (tauri-specta default: PascalCase).

export const events = {
  // StreamChunk — emitted for each streaming chunk from the agent
  streamChunk: createEvent<import("@/shared/types").StreamChunk>("StreamChunk"),

  // AgentPermissionRequest — agent requests permission for a dangerous tool
  agentPermissionRequest: createEvent<AgentPermissionRequestPayload>(
    "AgentPermissionRequest"
  ),

  // AgentFeedbackRequest — agent requests user feedback before continuing
  agentFeedbackRequest: createEvent<AgentFeedbackRequestPayload>(
    "AgentFeedbackRequest"
  ),

  // AgentReviewFindingsRequest — agent requests review of its findings
  agentReviewFindingsRequest: createEvent<AgentReviewFindingsRequestPayload>(
    "AgentReviewFindingsRequest"
  ),

  // SubtaskCreated — agent created a child ticket
  subtaskCreated: createEvent<import("@/shared/types").SubtaskCreatedEvent>(
    "SubtaskCreated"
  ),

  // SubtaskUpdated — agent updated a child ticket
  subtaskUpdated: createEvent<import("@/shared/types").SubtaskUpdatedEvent>(
    "SubtaskUpdated"
  ),

  // SubtaskClosed — agent closed a child ticket
  subtaskClosed: createEvent<import("@/shared/types").SubtaskClosedEvent>(
    "SubtaskClosed"
  ),

  // SectionUpdateEvent — agent updated a ticket section
  sectionUpdateEvent: createEvent<import("@/shared/types").SectionUpdateEvent>(
    "SectionUpdateEvent"
  ),

  // NotificationEvent — agent sent a notification
  notificationEvent: createEvent<import("@/shared/types").NotificationEvent>(
    "NotificationEvent"
  ),

  // StepCompleteEvent — agent completed a workflow step
  stepCompleteEvent: createEvent<import("@/shared/types").StepCompleteEvent>(
    "StepCompleteEvent"
  ),

  // StatusUpdateEvent — agent provided a status update
  statusUpdateEvent: createEvent<import("@/shared/types").StatusUpdateEvent>(
    "StatusUpdateEvent"
  ),

  // PrUrlReportedEvent — agent reported a pull request URL
  prUrlReportedEvent: createEvent<PrUrlReportedEventPayload>(
    "PrUrlReportedEvent"
  ),

  // AppPreferences — cross-window sync when preferences change
  appPreferences: createEvent<AppPreferences>("AppPreferences"),
};
